const Q_ECONOMICS_2002=[{"id": "objective>Economics>2002>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The elasticity of supply of perishable goods is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Unitary </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Inelastic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Zero</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Elastic</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The types of goods which gets degraded or spoiled in less span of time when not stored properly are called as perishable goods. On the other hand, the \"elasticity of supply\" is defined as the percent \"change in the quantity\" supply over the percent \"change in the price\" of the commodity. <br/>  <br/>   Inelastic supply refers to the condition, in which the percent \"change in the quantity\" supply over the percent \"change in the price\" of the commodity is compared when the former is increased, the latter is also increased. Such type of supply is seen in the \"case of\" perishable goods.\"</div>", "topic": "THEORY OF SUPPLY : ELASTICITY OF SUPPLY"}, {"id": "objective>Economics>2002>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The demand for factors of production is an example of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">joint demand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">competitive demand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">derived demand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">composite demand</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Derived demand is a demand for a commodity, service, etc. which is a consequence of the demand for something else.since factors of production is not acquired for immediate consumption but to produce other goods therefore,it is a derived demand.</div>", "topic": "THEORY OF DEMAND : TYPES OF DEMAND"}, {"id": "objective>Economics>2002>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  In the diagram above, the marginal rate of substitution of <strong>X</strong> and <strong>Y</strong> for a movement from <strong>S</strong> to <strong>T</strong> is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">13:3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1:5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">18:4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5:1</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">MRS<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">XY</span> = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">∆Y</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\"> ∆X</span> <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">MRS<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">XY</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">18 - 13<hr size=\"1\" />4 - 3</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">5:1</td><td style=\"text-align:center;\"></td></tr></table></div> </div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : MARGINAL RATE OF SUBSTITUTION (MRS)"}, {"id": "objective>Economics>2002>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A student has ₦30.00 with which to buy a ruler costing ₦18.00 and an exercise book costing N25.00. If he buys the exercise book, his opportunity cost is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the ruler</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the exercise book</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦25.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦18.00</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is the ruler, as it is the alternative foregone.Opportunity cost is the buying of an item at the expense of the other.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONCEPT"}, {"id": "objective>Economics>2002>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A shift in supply curve indicates that a different quantity will be supplied at each possible price because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">consumers are willing to pay higher prices</div>", "<div style=\"font-family:Cambria;font-size:17px;\">supply is facing competition </div>", "<div style=\"font-family:Cambria;font-size:17px;\">other factors than price have changed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">price has changed</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A shift in supply curve indicates that a different quantity will be supplied at each possible price because supply of a commodity changes due to change in any factor other than the own price of the commodity. The factors are : Technology, Cost of production, Government policy etc.</div>", "topic": "THEORY OF SUPPLY : DISTINCTION BETWEEN CHANGE IN QUANTITY SUPPLIED AND CHANGE IN SUPPLY"}, {"id": "objective>Economics>2002>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  In the pie chart above, the percentage for children is equivalent to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">288<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">72<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">90<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">144<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">the percentage for children is equivalent to  <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">40<hr size=\"1\" />100</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">360<hr size=\"1\" />1</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">144°</td></tr></table></div>.</div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY"}, {"id": "objective>Economics>2002>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If goods P and Q are purchased by a consumer, a fall in the price of P with the price of Q unchanged will cause the budget line to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">shift parallel inwards</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rotate outwards away from the origin </div>", "<div style=\"font-family:Cambria;font-size:17px;\">rotate inwards towards the origin </div>", "<div style=\"font-family:Cambria;font-size:17px;\">shift parallel outwards</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An increase in the price of a commodity will shift the budget line inward (Leftward) and vice versa while an increase in income of a consumer will shift the budget line outward (right ward) and vice versa.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : BUDGET LINE"}, {"id": "objective>Economics>2002>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the reasons for an exceptional demand curve is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">expectation of a future change in price</div>", "<div style=\"font-family:Cambria;font-size:17px;\">availability of credit facilities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">change in the price of the commodity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">availability of substitutes</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Exceptional demand curve is due to : <br/> - Fear of future rise in price <br/> - Consumer ignorance <br/> - Article of ostentation  <br/> - Luxury goods</div>", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>2002>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A scientific approach in economic analysis entails </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a deductive method only </div>", "<div style=\"font-family:Cambria;font-size:17px;\">both inductive and normative methods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a normative method only </div>", "<div style=\"font-family:Cambria;font-size:17px;\">both inductive and deductive methods</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A scientific approach in economic analysis entails both inductive and deductive methods. Inductive reasoning involves making broad generalizations from specific observations. In economics, this could involve observing economic events, collecting data, and then developing a theory to explain these phenomena. Deductive reasoning, on the other hand, starts out with a general statement, or hypothesis, and examines the possibilities to reach a specific, logical conclusion. In economics, this could involve starting with a theory and then testing it with data. Therefore, a scientific approach in economic analysis would involve both methods.</div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : SCIENTIFIC APPROACH"}, {"id": "objective>Economics>2002>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a centrally planned economy, the economic problem of deciding what to produce is dependent on</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">average profit </div>", "<div style=\"font-family:Cambria;font-size:17px;\">state command</div>", "<div style=\"font-family:Cambria;font-size:17px;\">average cost </div>", "<div style=\"font-family:Cambria;font-size:17px;\">relative prices</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is dependant on state command. This economy will most likely be a socialist economy.in a centrally planned economy,the means of production and distribution is determined by government or state.</div>", "topic": "ECONOMIC SYSTEM : ECONOMIC PROBLEMS OF THE SOCIETY"}, {"id": "objective>Economics>2002>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The solution to the problem of double coincidence of wants requires a buyer and a seller whose demands are precisely</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">competitive</div>", "<div style=\"font-family:Cambria;font-size:17px;\">composite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">supplementary</div>", "<div style=\"font-family:Cambria;font-size:17px;\">complementary</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Both individual good must complement each other to accomplish the problem of double coincidence of wants.</div>", "topic": "MONEY : FUNCTIONS OF MONEY"}, {"id": "objective>Economics>2002>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The stock exchange is a market for the buying and selling of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">monetary instruments </div>", "<div style=\"font-family:Cambria;font-size:17px;\">new shares</div>", "<div style=\"font-family:Cambria;font-size:17px;\">existing shares</div>", "<div style=\"font-family:Cambria;font-size:17px;\">treasury bills</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A stock exchange is an exchange or stock market where stock brokers and traders can buy and/or sell stocks (also called shares), bonds, and other securities.sometimes second-hand securities which are majorly long term.</div>", "topic": "FINANCIAL INSTITUTION : DEVELOPMENT, MERCHANT, MORTGAGE BANK ETC"}, {"id": "objective>Economics>2002>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">National Income estimates can be used to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">differentiate between the rich and the poor in a country</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prepare a country's annual budget </div>", "<div style=\"font-family:Cambria;font-size:17px;\">project the level of a country's economic development </div>", "<div style=\"font-family:Cambria;font-size:17px;\">compare a country's growth rate with that of another over a period of time </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">National income estimate can be used to determine: <br/> - Indices of Economic Welfare <br/> - Economic Planning <br/> - International Comparison of Living Standards <br/> - the rate of growth of the economy</div>", "topic": "NATIONAL INCOME : MEASUREMENT OF NATIONAL INCOME"}, {"id": "objective>Economics>2002>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In Nigeria, the bank that can correctly be described as a unit bank is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the Central Bank </div>", "<div style=\"font-family:Cambria;font-size:17px;\">people's bank</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mortgage bank</div>", "<div style=\"font-family:Cambria;font-size:17px;\">community bank</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A unit bank is a type of bank that provides banking services in one location and does not have branch networks. In Nigeria, the bank that fits this description is the community bank.</div>", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS"}, {"id": "objective>Economics>2002>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the country's GNP in the current year is ₦65 billion and the GNP in the base year ₦50 billion, the GNP deflator is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">130.0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">30.0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">15.0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.3</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">GNP deflator = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">GNP Current year </span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">  GNP base year</span>  x  100  <br/>  <br/>  = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">₦65billion </span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\"> ₦50billion </span> x  100 <br/>   <br/>  =   130</div>", "topic": "NATIONAL INCOME : CONCEPT"}, {"id": "objective>Economics>2002>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a closed economy, the marginal propensity to consume is 0.6 and the average propensity to consume is 0.8. The value of the multiplier is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.6</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.7</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.4</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a closed economy, the multiplier is calculated as 1/(1-Marginal Propensity to Consume). Given that the Marginal Propensity to Consume (MPC) is 0.6, the multiplier would be 1/(1-0.6) = 2.5. Therefore, the correct answer is 2.5.</div>", "topic": "EQUILIBRIUM LEVEL OF NATIONAL INCOME : THE CONCEPT OF MULTIPLIER"}, {"id": "objective>Economics>2002>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Insurance companies invest mainly in instruments traded on the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">capital market</div>", "<div style=\"font-family:Cambria;font-size:17px;\">commodity market</div>", "<div style=\"font-family:Cambria;font-size:17px;\">money market</div>", "<div style=\"font-family:Cambria;font-size:17px;\">open market</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Insurance companies are institutions in the Capital market. Capital market is a market where buyers and sellers engage in trade of financial securities like bonds, stocks, etc.</div>", "topic": "FINANCIAL INSTITUTION : DEVELOPMENT, MERCHANT, MORTGAGE BANK ETC"}, {"id": "objective>Economics>2002>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Liquidity preference refers to the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">need to borrow money for short periods to meet some temporary crises </div>", "<div style=\"font-family:Cambria;font-size:17px;\">wish to hold more funds for precautionary purposes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">need to increase the money supply in order to lower the interest rate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">demand to hold money as assets rather than as stocks</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Liquidity Preference refers to the additional premium which holders of wealth or investors will require in order to trade off cash and cash equivalents in exchange for those assets that are not so liquid. Among these might be government bonds, stocks, or real estate.</div>", "topic": "MONEY : DEMAND FOR MONEY"}, {"id": "objective>Economics>2002>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Creeping inflation implies that there is a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">gentle and persistent increase in the general price level </div>", "<div style=\"font-family:Cambria;font-size:17px;\">rapid and persistent increase in the general price level</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gentle but not permanent in the general price level</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rapid but not permanent increase in the general price level</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Creeping inflation is a term that means inflation is rising enough to be noticeable, but is still low by normal standards. In this condition, inflation tends to rise further and further over time.</div>", "topic": "INFLATION & DEFLATION : TYPES"}, {"id": "objective>Economics>2002>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The primary objective of the NDIC is  to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">give protection to the CBN against fraud</div>", "<div style=\"font-family:Cambria;font-size:17px;\">provide regulations guiding the finance houses</div>", "<div style=\"font-family:Cambria;font-size:17px;\">give protection against fraud</div>", "<div style=\"font-family:Cambria;font-size:17px;\">give protection to bank depositors</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria Deposit Insurance Corporation is an independent agency of the Federal Government of Nigeria. The objective of the deposit insurance system is to protect depositors and guarantee payment of insured funds in the event of failure of insured institutions.</div>", "topic": "FINANCIAL INSTITUTION : INTRODUCTION"}, {"id": "objective>Economics>2002>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Excess demand inflation can be controlled through </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">contractionary fiscal policy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">contractionary trade policy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">expansionary fiscal policy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">expansionary monetary policy</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Contractionary fiscal policy is the use of taxes to control inflation in an economy. In order to control inflation,  the government can increase the tax rate.</div>", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL"}, {"id": "objective>Economics>2002>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The middlemen in the chain of distribution are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">manufacturers and consumers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wholesalers and retailers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">consumers and wholesalers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">retailers and consumers</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The distribution channel starts with the producer and ends with the consumer. In between, there are intermediaries or middlemen. These middlemen are also known as Agent middlemen which are: The wholesalers and retailers.</div>", "topic": "DISTRIBUTIVE TRADE : THE MIDDLEMEN"}, {"id": "objective>Economics>2002>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the growth rate of available resources continuously outpaces that of the population, a country will eventually experience</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">maximum population</div>", "<div style=\"font-family:Cambria;font-size:17px;\">underpopulation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">overpopulation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">optimum population</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Under population exists when a population is too small, therefore unable to fully utilise the available resource endowments. Under population is also characterised by a situation where the available resources are capable of supporting a much larger population with no reduction in living standards.</div>", "topic": "POPULATION : OVER POPULATION, UNDER POPULATION"}, {"id": "objective>Economics>2002>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The equilibrium wage in an economy is determined by the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">public service</div>", "<div style=\"font-family:Cambria;font-size:17px;\">workers' union</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rate of inflation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">supply and demand for labour</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The equilibrium wage rate is determined when the demand for labour equates the supply of labour. At that point, the wage rate is determined.</div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT : DEMAND FOR LABOUR"}, {"id": "objective>Economics>2002>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Malthusian theory of population growth is often said to be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ambiguous</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oversimplified</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pessimistic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">optimistic</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">He wrote that population growth occurs exponentially, so it increases according to birth rate. For example, if every member of a family tree reproduces, the tree will continue to grow with each generation. On the other hand, food production increases arithmetically, so it only increases at given points in time. Malthus wrote that, left unchecked, populations can outgrow their resources. It is said to be pessimistic.</div>", "topic": "POPULATION : THEORIES OF POPULATION"}, {"id": "objective>Economics>2002>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Improved labour efficiency can be measured by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an increase in output-input ratio</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in output-input ratio</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the constancy of input-output ratio</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in input-output ratio</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Improved labour efficiency can be measured by an increase in output-input ratio. This is because labour efficiency refers to the amount of goods and services (output) that a worker produces in a given amount of time (input). Therefore, if the output-input ratio increases, it means that a worker is able to produce more goods and services in the same amount of time, indicating improved labour efficiency.</div>", "topic": "THEORY OF PRODUCTION (1) : DIVISION OF LABOUR & SPECIALISATION"}, {"id": "objective>Economics>2002>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">As a firm increases its output, the average fixed cost </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tends to rise continuously </div>", "<div style=\"font-family:Cambria;font-size:17px;\">remains constant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rises and then falls</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tends to decrease continuously</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the short run, when the output of a firm increases, its average fixed cost decreases and cannot touch the x- axis or be equal to zero.</div>", "topic": "THE CONCEPT OF COST & REVENUE : SHORT RUN & LONG RUN COST"}, {"id": "objective>Economics>2002>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  In the diagram above, what is the excess demand at the price of ₦60?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">200</div>", "<div style=\"font-family:Cambria;font-size:17px;\">300</div>", "<div style=\"font-family:Cambria;font-size:17px;\">600</div>", "<div style=\"font-family:Cambria;font-size:17px;\">100</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">From the diagram above,  At ₦60: excess demand will be 300 units - 100 units <br/>  = 200 units.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : DETERMINANTS OF PRICE UNDER FREE MARKET"}, {"id": "objective>Economics>2002>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The short-run equilibrium output for a monopolist is determined by the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">highest point on the total revenue curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">minimum point on the average cost curve </div>", "<div style=\"font-family:Cambria;font-size:17px;\">intersection of the average revenue and the average cost curves</div>", "<div style=\"font-family:Cambria;font-size:17px;\">intersection of the marginal cost and marginal revenue curves</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A monopolist produces the profit-maximizing quantity of output that equates marginal revenue and marginal cost. This production level can be identified using total revenue and cost, marginal revenue and cost, or profit. Because a monopoly faces a negatively-sloped demand curve, it does not efficiently allocate resources by equating price and marginal cost.</div>", "topic": "MARKET STRUCTURE : IMPERFECT MARKET ( MONOPOLY)"}, {"id": "objective>Economics>2002>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The benefits that accrue to a firm as a result of an improvement in the industry it belongs to are called </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">internal economics of scale</div>", "<div style=\"font-family:Cambria;font-size:17px;\">economics of scale </div>", "<div style=\"font-family:Cambria;font-size:17px;\">market economics</div>", "<div style=\"font-family:Cambria;font-size:17px;\">external economics</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">External economies of scale will increase the productivity of an entire industry, geographical area or economy. The external factors are outside the control of a particular company, and encompass positive externalities that reduce the firm's costs.</div>", "topic": "THEORY OF PRODUCTION (1) : SCALE OF PRODUCTION"}, {"id": "objective>Economics>2002>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the short run, a firm marginal cost curve above the point of shut-down is its</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">demand curve </div>", "<div style=\"font-family:Cambria;font-size:17px;\">supply curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cost curve </div>", "<div style=\"font-family:Cambria;font-size:17px;\">purchase curve</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the short run, a firm's willingness to produce should continue up until the point where its marginal cost curve is no longer above average variable costs. The supply curve in a short-run perfect equilibrium model is the marginal cost curve above the average variable cost curve.</div>", "topic": "MARKET STRUCTURE : PERFECT MARKET"}, {"id": "objective>Economics>2002>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The economic policy of deregulation is aimed at encouraging </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a monopolistic market structure </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a duopolistic market structure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a competitive market structure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an oligopolistic market structure</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Deregulation is the reduction or elimination of government power in a particular industry, usually enacted to create more competition within the industry.The main objectives of deregulation include: introducing a market economy; increasing economic efficiency; establishing democracy and guaranteeing political freedom and increasing government revenue.</div>", "topic": "ECONOMIC DEVELOPMENT : INTRODUCTION"}, {"id": "objective>Economics>2002>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Under conditions of perfect competition, a firm's supply curve is determined by its </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">total cost curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marginal cost curve </div>", "<div style=\"font-family:Cambria;font-size:17px;\">variable cost curve </div>", "<div style=\"font-family:Cambria;font-size:17px;\">fixed cost curve</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is determined by the marginal cost curve. The marginal cost curve represent the supply curve of a firm.</div>", "topic": "MARKET STRUCTURE : PERFECT MARKET"}, {"id": "objective>Economics>2002>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The effect of an increase in demand for a commodity accompanied by a decrease in supply will be to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">raise the price of the commodity and affect the quantity in an indeterminate way</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decrease the equilibrium quantity and affect the price in an intermediate way</div>", "<div style=\"font-family:Cambria;font-size:17px;\">raise its price as  well as the equilibrium quantity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">lower its price while affecting the equilibrium quantity in an indeterminate way</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The effect of an increase in demand for a commodity accompanied by a decrease in supply will be to raise the price of the commodity and affect the quantity in an indeterminate way. This is because an increase in demand, all else being equal, will increase the price and quantity of a commodity. However, a decrease in supply, all else being equal, will increase the price but decrease the quantity of a commodity. Therefore, the overall effect on quantity is indeterminate as it depends on the relative magnitudes of the demand and supply changes.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : EFFECT OF CHANGE IN SUPPLY & DEMAND ON EQUILIBRIUM PRICE & QUANTITY"}, {"id": "objective>Economics>2002>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">External finance for a limited liability company is mainly sourced through</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the leasing of equipment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the issuing of shares</div>", "<div style=\"font-family:Cambria;font-size:17px;\">trade credits</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bank loans</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">External finance for a limited liability company is mainly sourced through the issuing of shares. This is because a limited liability company is a type of business structure where the company has the legal rights of an individual, and can thus issue shares to raise capital. The issuing of shares involves selling a portion of ownership in the company to raise funds.</div>", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES"}, {"id": "objective>Economics>2002>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Some of the key indicators of underdevelopment in a country are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">poverty, high level of literacy and low income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">poverty, low level of literacy and low income </div>", "<div style=\"font-family:Cambria;font-size:17px;\">low level of illiteracy, low income and poverty</div>", "<div style=\"font-family:Cambria;font-size:17px;\">poverty, low income and low unemployment level</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Indicators of underdevelopment include: high birth rates, high infant mortality, undernourishment, a large agricultural and small industrial sector, low per capita GDP, high levels of illiteracy, and low life expectancy.</div>", "topic": "ECONOMIC DEVELOPMENT : INDICATORS OF GROWTH & DEVELOPMENT"}, {"id": "objective>Economics>2002>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the roles of NNPC in the production and refining of crude oil is to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">secure maximum government revenue and regulate price </div>", "<div style=\"font-family:Cambria;font-size:17px;\">prevent smuggling of petroleum products </div>", "<div style=\"font-family:Cambria;font-size:17px;\">satisfy the domestic consumption of petroleum products</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protect the local operators in the petroleum industry</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Nigerian National Petroleum Corporation (NNPC) is the oil corporation through which the federal government of Nigeria regulates and participates in the country's petroleum industry. One of its roles is to secure maximum government revenue and regulate price. This is done through the exploration, production, and marketing of petroleum and petroleum products. It is also responsible for enforcing price regulations to ensure that petroleum products are sold at the right prices.</div>", "topic": "PETROLEUM AND THE NIGERIA ECONOMY : NNPC"}, {"id": "objective>Economics>2002>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One way of correcting the balance of payments problem of a country is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">introduce import promotion measures</div>", "<div style=\"font-family:Cambria;font-size:17px;\">buy investments abroad </div>", "<div style=\"font-family:Cambria;font-size:17px;\">devalue the currency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">de-emphasize import-substitution industries</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Devaluating a country's currency is one of the ways used in correcting a balance of payment problem. The term Devaluation means a reduction in the official rate at which one currency is exchanged for another. It is done to make export attractive by making imports expensive.</div>", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT"}, {"id": "objective>Economics>2002>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following yields more revenue to Nigeria?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Value added tax</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Royalties</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Indirect tax</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Direct tax</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Value added tax is form of indirect tax on the consumption of goods and services. VAT has been a significant source of revenue for Nigeria, especially with the increase in rates and the broadening of tax base. <br/>  <br/> Indirect tax includes various taxes that are not directly paid by individuals but are instead levied on goods and services, such as excise duties and import duties. While these can also generate substantial revenue, their contribution may fluctuate based in trade policies and economic activity.</div>", "topic": "PUBLIC FINANCE : CLASSIFICATION OF TAX"}, {"id": "objective>Economics>2002>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Import substitution aims at </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">substituting agricultural products with industrial ones</div>", "<div style=\"font-family:Cambria;font-size:17px;\">substituting imports with agricultural exports</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the diversification of industries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">improving the balance of payments</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Import substitution is a trade and economic policy which advocates replacing foreign imports with domestic production. It is based on the premise that a country should attempt to reduce its foreign dependency through the local production of industrialized products.</div>", "topic": "INTERNATIONAL TRADE : ECONOMIC INTEGRATION IN AFRICA"}, {"id": "objective>Economics>2002>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the major criticisms of the 1962-1968 National Development Plan was that </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">it failed to incorporate lessons gained from earlier plans to enhance its efficiency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it came too quickly after the country's independence </div>", "<div style=\"font-family:Cambria;font-size:17px;\">planned expenditure was based too heavily on expected earnings from crude oil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">its execution was based largely on foreign sourced financial resources</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The first Nigerian National Development Plan was an ambitious economic plan that was launched in 1962 with a six year target that envisaged the spending of about $1,900,000,000 on development and productivity enhancing projects and half of this amount was to come from external sources.</div>", "topic": "ECONOMIC DEVELOPMENT : DEVELOPMENT PLANNING"}, {"id": "objective>Economics>2002>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A deficit budget can be used to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">stimulate recovery from a trade depression</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protect the economy from inflation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">starve the economy of funds for economic development </div>", "<div style=\"font-family:Cambria;font-size:17px;\">provide measures to remedy the balance of payments</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A deficit budget, which is a budget in which expenditures exceed revenue, can be used to stimulate recovery from a trade depression. This is because government spending can stimulate economic activity, leading to increased production, employment, and income. This concept is based on Keynesian economics, which advocates for increased government expenditures and lower taxes to stimulate demand and pull the global economy out of depression.</div>", "topic": "PUBLIC FINANCE : FISCAL POLICY"}, {"id": "objective>Economics>2002>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">ECOWAS has taken a giant step towards economic integration by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">presenting a united front against foreign economic exploiters</div>", "<div style=\"font-family:Cambria;font-size:17px;\">introducing a common currency for travellers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">holding frequent meetings at various state capitals </div>", "<div style=\"font-family:Cambria;font-size:17px;\">increasing economic stability among member states</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Economic Community of West African States (ECOWAS) has taken a significant step towards economic integration by introducing a common currency for travellers. This is a part of their broader goal to create a single large trading bloc through economic cooperation. Increased economic integration is expected to lead to economic liberalization and free trade, thus promoting economic growth in the region.</div>", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : OPEC, ECA, IMF"}, {"id": "objective>Economics>2002>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the major factors militating against industrialization in Nigeria is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">inadequacy of infrastructural facilities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">absence of government participation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">frequent breakdown of equipment </div>", "<div style=\"font-family:Cambria;font-size:17px;\">failure to get foreign partners and supporters</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">inadequacy of infrastructural facilities, shortgage of raw materials, insufficient capital, poor quality of industrial labour etc are the problems of industrialisation or industrial growth in Nigeria.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : COMMERCIALISATION & PRIVATISATION"}, {"id": "objective>Economics>2002>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The types, sources and uses of government income are mainly concerned with </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">public expenditure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">public revenue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">public budget  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">public finance</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The types, sources and uses of government income are mainly concerned with public revenue. Public revenue refers to the income generated by the government through taxation, public enterprises, and other sources. It is used to fund public goods and services, pay government obligations, and provide for the general welfare of the society.</div>", "topic": "PUBLIC FINANCE : INTRODUCTION"}, {"id": "objective>Economics>2002>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The present privatization policy in Nigeria is aimed at </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reducing income inequality</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reducing the prices of goods and services</div>", "<div style=\"font-family:Cambria;font-size:17px;\">poverty alleviation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increasing efficiency in production</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is aimed at increasing efficiency in production. It is the transfer of ownership of property or businesses from a government to a privately owned entity. In Nigeria, it is handled by the Bureau of Public Enterprises.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : INDIGENISATION & NATIONALISATION"}, {"id": "objective>Economics>2002>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the problems arising from the localization of industries is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">high prices of output</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the exportation of output</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the scarcity of foreign exchange</div>", "<div style=\"font-family:Cambria;font-size:17px;\">structural unemployment </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Structural Unemployment is unemployment resulting from industrial reorganization, typically due to technological change, rather than fluctuations in supply or demand.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION"}, {"id": "objective>Economics>2002>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major purpose of African Development Bank is to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">provide loans for trade development </div>", "<div style=\"font-family:Cambria;font-size:17px;\">provide loans for infrastructural development </div>", "<div style=\"font-family:Cambria;font-size:17px;\">provide loans for development banks in distress</div>", "<div style=\"font-family:Cambria;font-size:17px;\">educate peasant farmers in new techniques</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The African Development Bank Group is a multilateral development finance institution established to contribute to the economic development and social progress of African countries.</div>", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : IBRD, AFDB, UNCTAD ETC"}, {"id": "objective>Economics>2002>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">As a country gets more developed, the percentage of labour engaged in agriculture tends to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">remain constant </div>", "<div style=\"font-family:Cambria;font-size:17px;\">decrease steadily </div>", "<div style=\"font-family:Cambria;font-size:17px;\">switch over to trading </div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase steadily</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It tends to decrease steadily, as the labour becomes more interested in the secondary and tertiary sectors.</div>", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION"}, {"id": "objective>Economics>2002>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  In the diagram above, the opportunity cost of a unit cotton in terms of cocoa is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4 for Ghana; 2 for Nigeria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20 for Ghana; 60 for Nigeria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1/4 for Ghana, 1/2 for Nigeria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5 for Ghana; 30 for Nigeria</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">For</td><td style=\"text-align:center;\">Ghana</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">5<hr size=\"1\" />20</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />4</td></tr></table></div>  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">For</td><td style=\"text-align:center;\">Nigeria</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">30<hr size=\"1\" />60</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td></tr></table></div>.</div>", "topic": "INTERNATIONAL TRADE : TERMS OF TRADE"}];
